/**
 * Generate message test data based on pattern
 *
 * @param pattern - The test data pattern to generate
 * @param overrides - Optional field overrides
 * @returns Generated test data
 *
 * @example
 * ```typescript
 * // Generate complete test data
 * const data = generateMessageTestData('complete');
 *
 * // Generate unique test data with overrides
 * const customData = generateMessageTestData('unique', {
 *   is_active: false,
 * });
 * ```
 */
export function generateMessageTestData(
  pattern: TestDataPattern = 'complete',
  overrides: Partial<MessageCreateRequest> = {}
): MessageCreateRequest {
  let baseData: MessageCreateRequest;

  switch (pattern) {
    case 'minimal':
      baseData = { ...minimalMessageFixture };
      break;

    case 'complete':
      baseData = { ...completeMessageFixture };
      break;

    case 'invalid':
      // Return invalid data (caller should handle validation failure)
      baseData = { ...invalidMessageFixture } as MessageCreateRequest;
      break;

    case 'unique':
      // Generate fresh unique values for each call
      baseData = {
        ...uniqueMessageFixture,
      };
      break;

    default:
      baseData = { ...completeMessageFixture };
  }

  return { ...baseData, ...overrides };
}

